\\xb030dd36f0283b1d1d76cd7fea5b1cb4dc5a769369b09a3e00dfa6777774ca4a	11	{"database":2,"type":"native","native":{"template-tags":{},"query":"WITH edades AS (\\n    SELECT\\n        o.sector_empresarial,\\n        e.edad\\n    FROM organizacion_empresario oe\\n    INNER JOIN organizations o ON oe.organizacionId = o.id\\n    INNER JOIN empresarios e   ON oe.empresarioId   = e.id\\n),\\nconteos AS (\\n    SELECT\\n        sector_empresarial,\\n        edad,\\n        COUNT(*) AS frecuencia\\n    FROM edades\\n    GROUP BY sector_empresarial, edad\\n),\\nordenadas AS (\\n    SELECT\\n        sector_empresarial,\\n        edad,\\n        frecuencia,\\n        ROW_NUMBER() OVER (\\n            PARTITION BY sector_empresarial\\n            ORDER BY frecuencia DESC\\n        ) AS rn\\n    FROM conteos\\n)\\nSELECT\\n    sector_empresarial,\\n    edad AS moda_edad,\\n    frecuencia\\nFROM ordenadas\\nWHERE rn = 1\\nORDER BY sector_empresarial;\\n"},"middleware":{"js-int-to-string?":true,"userland-query?":true,"add-default-userland-constraints?":true}}
\\xd52b42f1c5b9fe4dc50c3bfa1793e7a8238abfb0bca8833525523cc8ce4bafba	9	{"database":2,"type":"native","native":{"template-tags":{},"query":"SELECT actividad, edad_moda\\nFROM (\\n    -- PESCA\\n    SELECT\\n        'pesca' AS actividad,\\n        (\\n            SELECT e2.edad\\n            FROM organizacion_empresario oe2\\n            INNER JOIN organizations o2 ON oe2.organizacionId = o2.id\\n            INNER JOIN empresarios e2 ON oe2.empresarioId = e2.id\\n            WHERE o2.pesca = 1\\n            GROUP BY e2.edad\\n            ORDER BY COUNT(*) DESC\\n            LIMIT 1\\n        ) AS edad_moda\\n\\n    UNION ALL\\n\\n    -- AGRICULTURA\\n    SELECT\\n        'agricultura' AS actividad,\\n        (\\n            SELECT e2.edad\\n            FROM organizacion_empresario oe2\\n            INNER JOIN organizations o2 ON oe2.organizacionId = o2.id\\n            INNER JOIN empresarios e2 ON oe2.empresarioId = e2.id\\n            WHERE o2.agricultura = 1\\n            GROUP BY e2.edad\\n            ORDER BY COUNT(*) DESC\\n            LIMIT 1\\n        ) AS edad_moda\\n\\n    UNION ALL\\n\\n    -- AGROINDUSTRIA\\n    SELECT\\n        'agroindustria' AS actividad,\\n        (\\n            SELECT e2.edad\\n            FROM organizacion_empresario oe2\\n            INNER JOIN organizations o2 ON oe2.organizacionId = o2.id\\n            INNER JOIN empresarios e2 ON oe2.empresarioId = e2.id\\n            WHERE o2.agroindustria = 1\\n            GROUP BY e2.edad\\n            ORDER BY COUNT(*) DESC\\n            LIMIT 1\\n        ) AS edad_moda\\n\\n    UNION ALL\\n\\n    -- PECUARIO\\n    SELECT\\n        'pecuario' AS actividad,\\n        (\\n            SELECT e2.edad\\n            FROM organizacion_empresario oe2\\n            INNER JOIN organizations o2 ON oe2.organizacionId = o2.id\\n            INNER JOIN empresarios e2 ON oe2.empresarioId = e2.id\\n            WHERE o2.pecuario = 1\\n            GROUP BY e2.edad\\n            ORDER BY COUNT(*) DESC\\n            LIMIT 1\\n        ) AS edad_moda\\n) AS t\\nORDER BY actividad;\\n"},"middleware":{"js-int-to-string?":true,"userland-query?":true,"add-default-userland-constraints?":true}}
