\\xb5be24cb2a5bb81764900d046516df66ad58718c4d8ebf0dc609c61fb80982e1	38	{"constraints":{"max-results":10000,"max-results-bare-rows":2000},"type":"native","middleware":{"js-int-to-string?":true,"ignore-cached-results?":false,"process-viz-settings?":false,"userland-query?":true},"cache-strategy":null,"native":{"template-tags":{},"query":"SELECT actividad, edad_promedio\\nFROM (\\n    SELECT 'pesca' AS actividad, AVG(e.edad) AS edad_promedio\\n    FROM organizacion_empresario oe\\n    INNER JOIN organizations o ON oe.organizacionId = o.id\\n    INNER JOIN empresarios e ON oe.empresarioId = e.id\\n    WHERE o.pesca = 1\\n\\n    UNION ALL\\n\\n    SELECT 'agricultura', AVG(e.edad)\\n    FROM organizacion_empresario oe\\n    INNER JOIN organizations o ON oe.organizacionId = o.id\\n    INNER JOIN empresarios e ON oe.empresarioId = e.id\\n    WHERE o.agricultura = 1\\n\\n    UNION ALL\\n\\n    SELECT 'agroindustria', AVG(e.edad)\\n    FROM organizacion_empresario oe\\n    INNER JOIN organizations o ON oe.organizacionId = o.id\\n    INNER JOIN empresarios e ON oe.empresarioId = e.id\\n    WHERE o.agroindustria = 1\\n\\n    UNION ALL\\n\\n    SELECT 'pecuario', AVG(e.edad)\\n    FROM organizacion_empresario oe\\n    INNER JOIN organizations o ON oe.organizacionId = o.id\\n    INNER JOIN empresarios e ON oe.empresarioId = e.id\\n    WHERE o.pecuario = 1\\n) AS t\\nORDER BY actividad;\\n"},"viz-settings":{"graph.dimensions":["actividad","edad_promedio"],"graph.series_order_dimension":null,"graph.series_order":null,"stackable.stack_type":"stacked","graph.x_axis.scale":"ordinal","graph.metrics":["edad_promedio"]},"database":2}
\\xb009a36f794d624cbe0bfce05b9871af664251e549ecce546bdb563a0401fc73	274	{"constraints":{"max-results":10000,"max-results-bare-rows":2000},"type":"native","middleware":{"js-int-to-string?":true,"ignore-cached-results?":false,"process-viz-settings?":false,"userland-query?":true},"cache-strategy":null,"native":{"template-tags":{},"query":"SELECT actividad, edad_moda\\nFROM (\\n    -- PESCA\\n    SELECT\\n        'pesca' AS actividad,\\n        (\\n            SELECT e2.edad\\n            FROM organizacion_empresario oe2\\n            INNER JOIN organizations o2 ON oe2.organizacionId = o2.id\\n            INNER JOIN empresarios e2 ON oe2.empresarioId = e2.id\\n            WHERE o2.pesca = 1\\n            GROUP BY e2.edad\\n            ORDER BY COUNT(*) DESC\\n            LIMIT 1\\n        ) AS edad_moda\\n\\n    UNION ALL\\n\\n    -- AGRICULTURA\\n    SELECT\\n        'agricultura' AS actividad,\\n        (\\n            SELECT e2.edad\\n            FROM organizacion_empresario oe2\\n            INNER JOIN organizations o2 ON oe2.organizacionId = o2.id\\n            INNER JOIN empresarios e2 ON oe2.empresarioId = e2.id\\n            WHERE o2.agricultura = 1\\n            GROUP BY e2.edad\\n            ORDER BY COUNT(*) DESC\\n            LIMIT 1\\n        ) AS edad_moda\\n\\n    UNION ALL\\n\\n    -- AGROINDUSTRIA\\n    SELECT\\n        'agroindustria' AS actividad,\\n        (\\n            SELECT e2.edad\\n            FROM organizacion_empresario oe2\\n            INNER JOIN organizations o2 ON oe2.organizacionId = o2.id\\n            INNER JOIN empresarios e2 ON oe2.empresarioId = e2.id\\n            WHERE o2.agroindustria = 1\\n            GROUP BY e2.edad\\n            ORDER BY COUNT(*) DESC\\n            LIMIT 1\\n        ) AS edad_moda\\n\\n    UNION ALL\\n\\n    -- PECUARIO\\n    SELECT\\n        'pecuario' AS actividad,\\n        (\\n            SELECT e2.edad\\n            FROM organizacion_empresario oe2\\n            INNER JOIN organizations o2 ON oe2.organizacionId = o2.id\\n            INNER JOIN empresarios e2 ON oe2.empresarioId = e2.id\\n            WHERE o2.pecuario = 1\\n            GROUP BY e2.edad\\n            ORDER BY COUNT(*) DESC\\n            LIMIT 1\\n        ) AS edad_moda\\n) AS t\\nORDER BY actividad;\\n"},"viz-settings":{"graph.series_order":null,"graph.series_order_dimension":null,"graph.dimensions":["actividad","edad_moda"],"series_settings":{"edad_moda":{"color":"#A989C5"}},"stackable.stack_type":"stacked","graph.x_axis.scale":"ordinal","graph.metrics":["edad_moda"]},"database":2}
