76	2025-11-21 02:41:41.574935+00	2025-11-25 03:35:21.443752+00	Moda de la edad de las personas fundadoras por tipo de actividad productiva	\N	bar	{"database":2,"type":"native","native":{"template-tags":{},"query":"SELECT actividad, edad_moda\\nFROM (\\n    -- PESCA\\n    SELECT\\n        'pesca' AS actividad,\\n        (\\n            SELECT e2.edad\\n            FROM organizacion_empresario oe2\\n            INNER JOIN organizations o2 ON oe2.organizacionId = o2.id\\n            INNER JOIN empresarios e2 ON oe2.empresarioId = e2.id\\n            WHERE o2.pesca = 1\\n            GROUP BY e2.edad\\n            ORDER BY COUNT(*) DESC\\n            LIMIT 1\\n        ) AS edad_moda\\n\\n    UNION ALL\\n\\n    -- AGRICULTURA\\n    SELECT\\n        'agricultura' AS actividad,\\n        (\\n            SELECT e2.edad\\n            FROM organizacion_empresario oe2\\n            INNER JOIN organizations o2 ON oe2.organizacionId = o2.id\\n            INNER JOIN empresarios e2 ON oe2.empresarioId = e2.id\\n            WHERE o2.agricultura = 1\\n            GROUP BY e2.edad\\n            ORDER BY COUNT(*) DESC\\n            LIMIT 1\\n        ) AS edad_moda\\n\\n    UNION ALL\\n\\n    -- AGROINDUSTRIA\\n    SELECT\\n        'agroindustria' AS actividad,\\n        (\\n            SELECT e2.edad\\n            FROM organizacion_empresario oe2\\n            INNER JOIN organizations o2 ON oe2.organizacionId = o2.id\\n            INNER JOIN empresarios e2 ON oe2.empresarioId = e2.id\\n            WHERE o2.agroindustria = 1\\n            GROUP BY e2.edad\\n            ORDER BY COUNT(*) DESC\\n            LIMIT 1\\n        ) AS edad_moda\\n\\n    UNION ALL\\n\\n    -- PECUARIO\\n    SELECT\\n        'pecuario' AS actividad,\\n        (\\n            SELECT e2.edad\\n            FROM organizacion_empresario oe2\\n            INNER JOIN organizations o2 ON oe2.organizacionId = o2.id\\n            INNER JOIN empresarios e2 ON oe2.empresarioId = e2.id\\n            WHERE o2.pecuario = 1\\n 