40	Card	74	1	2025-11-21 02:02:12.429718+00	{"description":null,"archived":false,"collection_position":null,"source_card_id":null,"table_id":null,"card_schema":22,"database_id":2,"enable_embedding":false,"collection_id":5,"query_type":"native","name":"Edad promedio de las personas fundadoras por tipo de actividad productiva","type":"question","embedding_params":null,"cache_ttl":null,"dataset_query":{"database":2,"type":"native","native":{"template-tags":{},"query":"SELECT actividad, edad_promedio\\nFROM (\\n    SELECT 'pesca' AS actividad, AVG(e.edad) AS edad_promedio\\n    FROM organizacion_empresario oe\\n    INNER JOIN organizations o ON oe.organizacionId = o.id\\n    INNER JOIN empresarios e ON oe.empresarioId = e.id\\n    WHERE o.pesca = 1\\n\\n    UNION ALL\\n\\n    SELECT 'agricultura', AVG(e.edad)\\n    FROM organizacion_empresario oe\\n    INNER JOIN organizations o ON oe.organizacionId = o.id\\n    INNER JOIN empresarios e ON oe.empresarioId = e.id\\n    WHERE o.agricultura = 1\\n\\n    UNION ALL\\n\\n    SELECT 'agroindustria', AVG(e.edad)\\n    FROM organizacion_empresario oe\\n    INNER JOIN organizations o ON oe.organizacionId = o.id\\n    INNER JOIN empresarios e ON oe.empresarioId = e.id\\n    WHERE o.agroindustria = 1\\n\\n    UNION ALL\\n\\n    SELECT 'pecuario', AVG(e.edad)\\n    FROM organizacion_empresario oe\\n    INNER JOIN organizations o ON oe.organizacionId = o.id\\n    INNER JOIN empresarios e ON oe.empresarioId = e.id\\n    WHERE o.pecuario = 1\\n) AS t\\nORDER BY actividad;\\n"}},"parameter_mappings":[],"display":"bar","archived_directly":false,"collection_preview":true,"visualization_settings":{"graph.dimensions":["actividad","edad_promedio"],"graph.series_order_dimension":null,"graph.series_order":null,"stackable.stack_type":"stacked","graph.x_axis.scale":"ordinal","graph.metrics":["edad_promedio"]},"parameters":[],"dashboard_id":null}	f	t	\N	t	v0.56.13 (2455296)
