43	Card	75	1	2025-11-21 02:37:22.083684+00	{"description":null,"archived":false,"collection_position":null,"source_card_id":null,"table_id":null,"card_schema":22,"database_id":2,"enable_embedding":false,"collection_id":5,"query_type":"native","name":"Moda de la edad de las personas fundadoras por sector empresarial.","type":"question","embedding_params":null,"cache_ttl":null,"dataset_query":{"database":2,"type":"native","native":{"template-tags":{},"query":"WITH edades AS (\\n    SELECT\\n        o.sector_empresarial,\\n        e.edad\\n    FROM organizacion_empresario oe\\n    INNER JOIN organizations o ON oe.organizacionId = o.id\\n    INNER JOIN empresarios e   ON oe.empresarioId   = e.id\\n),\\nconteos AS (\\n    SELECT\\n        sector_empresarial,\\n        edad,\\n        COUNT(*) AS frecuencia\\n    FROM edades\\n    GROUP BY sector_empresarial, edad\\n),\\nordenadas AS (\\n    SELECT\\n        sector_empresarial,\\n        edad,\\n        frecuencia,\\n        ROW_NUMBER() OVER (\\n            PARTITION BY sector_empresarial\\n            ORDER BY frecuencia DESC\\n        ) AS rn\\n    FROM conteos\\n)\\nSELECT\\n    sector_empresarial,\\n    edad AS moda_edad,\\n    frecuencia\\nFROM ordenadas\\nWHERE rn = 1\\nORDER BY sector_empresarial;\\n"}},"parameter_mappings":[],"display":"bar","archived_directly":false,"collection_preview":true,"visualization_settings":{"graph.dimensions":["sector_empresarial"],"graph.series_order_dimension":null,"graph.series_order":null,"graph.x_axis.scale":"ordinal","graph.metrics":["moda_edad","frecuencia"]},"parameters":[],"dashboard_id":null}	f	f	\N	t	v0.56.13 (2455296)
42	Card	75	1	2025-11-21 02:34:48.180758+00	{"description":null,"archived":false,"collection_position":null,"source_card_id":null,"table_id":null,"card_schema":22,"database_id":2,"enable_embedding":false,"collection_id":5,"query_type":"native","name":"Moda de la edad de las personas fundadoras por sector empresarial.","type":"question","embedding_params":null,"cache_ttl":null,"dataset_query":{"database":2,"type":"native","native":{"template-tags":{},"query":"WITH edades AS (\\n    SELECT\\n        o.sector_empresarial,\\n        e.edad\\n    FROM organizacion_empresario oe\\n    INNER JOIN organizations o ON oe.organizacionId = o.id\\n    INNER JOIN empresarios e   ON oe.empresarioId   = e.id\\n),\\nconteos AS (\\n    SELECT\\n        sector_empresarial,\\n        edad,\\n        COUNT(*) AS frecuencia\\n    FROM edades\\n    GROUP BY sector_empresarial, edad\\n),\\nordenadas AS (\\n    SELECT\\n        sector_empresarial,\\n        edad,\\n        frecuencia,\\n        ROW_NUMBER() OVER (\\n            PARTITION BY sector_empresarial\\n            ORDER BY frecuencia DESC\\n        ) AS rn\\n    FROM conteos\\n)\\nSELECT\\n    sector_empresarial,\\n    edad AS moda_edad,\\n    frecuencia\\nFROM ordenadas\\nWHERE rn = 1\\nORDER BY sector_empresarial;\\n"}},"parameter_mappings":[],"display":"bar","archived_directly":false,"collection_preview":true,"visualization_settings":{"graph.dimensions":["sector_empresarial"],"graph.series_order_dimension":null,"graph.series_order":null,"graph.x_axis.scale":"ordinal","graph.metrics":["moda_edad","frecuencia"]},"parameters":[],"dashboard_id":null}	f	t	\N	f	v0.56.13 (2455296)
44	Card	76	1	2025-11-21 02:41:41.586841+00	{"description":null,"archived":false,"collection_position":null,"source_card_id":null,"table_id":null,"card_schema":22,"database_id":2,"enable_embedding":false,"collection_id":5,"query_type":"native","name":"Moda de la edad de las personas fundadoras por tipo de actividad productiva","type":"question","embedding_params":null,"cache_ttl":null,"dataset_query":{"database":2,"type":"native","native":{"template-tags":{},"query":"SELECT actividad, edad_moda\\nFROM (\\n    -- PESCA\\n    SELECT\\n        'pesca' AS actividad,\\n        (\\n            SELECT e2.edad\\n            FROM organizacion_empresario oe2\\n            INNER JOIN organizations o2 ON oe2.organizacionId = o2.id\\n            INNER JOIN empresarios e2 ON oe2.empresarioId = e2.id\\n            WHERE o2.pesca = 1\\n            GROUP BY e2.edad\\n            ORDER BY COUNT(*) DESC\\n            LIMIT 1\\n        ) AS edad_moda\\n\\n    UNION ALL\\n\\n    -- AGRICULTURA\\n    SELECT\\n        'agricultura' AS actividad,\\n        (\\n            SELECT e2.edad\\n            FROM organizacion_empresario oe2\\n            INNER JOIN organizations o2 ON oe2.organizacionId = o2.id\\n            INNER JOIN empresarios e2 ON oe2.empresarioId = e2.id\\n            WHERE o2.agricultura = 1\\n            GROUP BY e2.edad\\n            ORDER BY COUNT(*) DESC\\n            LIMIT 1\\n        ) AS edad_moda\\n\\n    UNION ALL\\n\\n    -- AGROINDUSTRIA\\n    SELECT\\n        'agroindustria' AS actividad,\\n        (\\n            SELECT e2.edad\\n            FROM organizacion_empresario oe2\\n            INNER JOIN organizations o2 ON oe2.organizacionId = o2.id\\n            INNER JOIN empresarios e2 ON oe2.empresarioId = e2.id\\n            WHERE o2.agroindustria = 1\\n            GROUP BY e2.edad\\n            ORDER BY COUNT(*) DESC\\n            LIMIT 1\\n        ) AS edad_moda\\n\\n    UNION ALL\\n\\n    -- PECUARIO\\n    SELECT\\n        'pecuario' AS actividad,\\n        (\\n            SELECT e2.edad\\n            FROM organizacion_empresario oe2\\n            INNER JOIN organizations o2 ON oe2.organizacionId = o2.id\\n            INNER JOIN empresarios e2 ON oe2.empresarioId = e2.id\\n            WHERE o2.pecuario = 1\\n            GROUP BY e2.edad\\n            ORDER BY COUNT(*) DESC\\n            LIMIT 1\\n        ) AS edad_moda\\n) AS t\\nORDER BY actividad;\\n"}},"parameter_mappings":[],"display":"bar","archived_directly":false,"collection_preview":true,"visualization_settings":{"graph.series_order":null,"graph.series_order_dimension":null,"graph.dimensions":["actividad","edad_moda"],"series_settings":{"edad_moda":{"color":"#A989C5"}},"stackable.stack_type":"stacked","graph.x_axis.scale":"ordinal","graph.metrics":["edad_moda"]},"parameters":[],"dashboard_id":null}	f	t	\N	t	v0.56.13 (2455296)
