53	Card	84	1	2025-11-22 22:46:51.795648+00	{"description":null,"archived":false,"collection_position":null,"source_card_id":null,"table_id":null,"card_schema":22,"database_id":2,"enable_embedding":false,"collection_id":5,"query_type":"native","name":"Organizacional (Tabla)","type":"question","embedding_params":null,"cache_ttl":null,"dataset_query":{"database":2,"type":"native","native":{"template-tags":{"id_empresa":{"type":"text","name":"id_empresa","id":"2f223604-5782-4c8b-8949-b0b357da628c","display-name":"ID Empresa"}},"query":"SELECT \\n    o.id AS id_empresa,\\n    o.nombre AS empresa,\\n    var.nombre AS area_funcional,\\n    ind.nombre AS indicador,\\n    it.id AS id_item,\\n    it.nombre AS item,\\n    ci.valor_opcion_seleccionada AS valor,\\n    op.nombre AS nivel_cumplimiento,\\n    ci.observaciones\\nFROM cuestionario_items ci\\nJOIN items it \\n    ON ci.idItem = it.id\\nJOIN indicador ind \\n    ON it.indicadorId = ind.id\\nLEFT JOIN indicador var \\n    ON ind.indicadorPadreId = var.id\\nJOIN cuestionario_organizacion co\\n    ON ci.idCuestionarioOrganizacion = co.id\\nJOIN organizations o \\n    ON co.idOrganizacion = o.id\\nLEFT JOIN opciones op\\n    ON op.valor_alfa = ci.valor_opcion_seleccionada\\n   AND op.rubricaId = it.rubricaId\\nWHERE var.nombre = 'Organizacional'\\n  AND o.id = {{id_empresa}}\\nORDER BY \\n    ind.nombre,\\n    it.id;\\n"}},"parameter_mappings":[],"display":"table","archived_directly":false,"collection_preview":true,"visualization_settings":{"table.pivot_column":"id_empresa","table.cell_column":"id_item"},"parameters":[{"id":"2f223604-5782-4c8b-8949-b0b357da628c","type":"string/=","target":["variable",["template-tag","id_empresa"]],"name":"ID Empresa","slug":"id_empresa","isMultiSelect":false}],"dashboard_id":null}	f	t	\N	t	v0.56.13 (2455296)
