ad productiva","collection_name":"Informes Generales","collection_authority_level":null,"creator_id":1,"updated_at":"2025-11-25T03:35:21.443752Z","moderated_status":null,"dataset_query":"{\\"database\\":2,\\"type\\":\\"native\\",\\"native\\":{\\"template-tags\\":{},\\"query\\":\\"SELECT actividad, edad_moda\\\\nFROM (\\\\n    -- PESCA\\\\n    SELECT\\\\n        'pesca' AS actividad,\\\\n        (\\\\n            SELECT e2.edad\\\\n            FROM organizacion_empresario oe2\\\\n            INNER JOIN organizations o2 ON oe2.organizacionId = o2.id\\\\n            INNER JOIN empresarios e2 ON oe2.empresarioId = e2.id\\\\n            WHERE o2.pesca = 1\\\\n            GROUP BY e2.edad\\\\n            ORDER BY COUNT(*) DESC\\\\n            LIMIT 1\\\\n        ) AS edad_moda\\\\n\\\\n    UNION ALL\\\\n\\\\n    -- AGRICULTURA\\\\n    SELECT\\\\n        'agricultura' AS actividad,\\\\n        (\\\\n            SELECT e2.edad\\\\n            FROM organizacion_empresario oe2\\\\n            INNER JOIN organizations o2 ON oe2.organizacionId = o2.id\\\\n            INNER JOIN empresarios e2 ON oe2.empresarioId = e2.id\\\\n            WHERE o2.agricultura = 1\\\\n            GROUP BY e2.edad\\\\n            ORDER BY COUNT(*) DESC\\\\n            LIMIT 1\\\\n        ) AS edad_moda\\\\n\\\\n    UNION ALL\\\\n\\\\n    -- AGROINDUSTRIA\\\\n    SELECT\\\\n        'agroindustria' AS actividad,\\\\n        (\\\\n            SELECT e2.edad\\\\n            FROM organizacion_empresario oe2\\\\n            INNER JOIN organizations o2 ON oe2.organizacionId = o2.id\\\\n            INNER JOIN empresarios e2 ON oe2.empresarioId = e2.id\\\\n            WHERE o2.agroindustria = 1\\\\n            GROUP BY e2.edad\\\\n            ORDER BY COUNT(*) DESC\\\\n            LIMIT 1\\\\n        ) AS edad_moda\\\\n\\\\n    UNION ALL\\\\n\\\\n    -- PECUARIO\\\\n    SELECT\\\\n        'pecuario' AS actividad,\\\\n        (\\\\n            SELECT e2.edad\\\\n            FROM organizacion_empresario oe2\\\\n            INNER JOIN organizations o2 ON oe2.organizacionId = o2.id\\\\n            INNER JOIN empresarios e2 ON oe2.empresarioId = e2.id\\\\n            WHERE o2.pecuario = 1\\\\n            GROUP BY e2.edad\\\\n            ORDER BY COUNT(*) DESC\\\\n            LIMIT 1\\\\n        ) AS edad_moda\\\\n) AS t\\\\nORDER BY actividad;\\\\n\\"}}","last_editor_id":1,"collection_location":"/","id":76,"last_edited_at":"2025-11-21T02:41:41.586841Z","dashboardcard_count":0,"collection_type":null,"display":"bar","archived_directly":false,"verified":null,"dashboard_id":null,"created_at":"2025-11-21T02:41:41.574935Z","model":"card"}	2026-03-03 23:19:16.763506+00	2026-03-03 23:19:16.763506+00	f	2025-11-25 03:35:21.443752+00	\N	f	5	\N	Moda de la edad de las personas fundadoras por tipo de actividad productiva	f	2025-11-21 02:41:41.586841+00	0	[]	\N	1	76	bar	2025-11-25 03:35:17.225569+00	2	1	4	2025-11-21 02:41:41.574935+00	\N
