ades\\\\n    GROUP BY sector_empresarial, edad\\\\n),\\\\nordenadas AS (\\\\n    SELECT\\\\n        sector_empresarial,\\\\n        edad,\\\\n        frecuencia,\\\\n        ROW_NUMBER() OVER (\\\\n            PARTITION BY sector_empresarial\\\\n            ORDER BY frecuencia DESC\\\\n        ) AS rn\\\\n    FROM conteos\\\\n)\\\\nSELECT\\\\n    sector_empresarial,\\\\n    edad AS moda_edad,\\\\n    frecuencia\\\\nFROM ordenadas\\\\nWHERE rn = 1\\\\nORDER BY sector_empresarial;\\\\n\\"}}","last_editor_id":1,"collection_location":"/","id":75,"last_edited_at":"2025-11-21T02:37:22.083684Z","dashboardcard_count":0,"collection_type":null,"display":"bar","archived_directly":false,"verified":null,"dashboard_id":null,"created_at":"2025-11-21T02:34:48.167677Z","model":"card"}	2026-03-04 01:16:00.522473+00	2026-03-04 01:16:00.522473+00	f	2025-11-25 03:34:38.222162+00	\N	f	5	\N	Moda de la edad de las personas fundadoras por sector empresarial.	f	2025-11-21 02:37:22.083684+00	0	[]	\N	1	75	bar	2025-11-25 03:35:29.288457+00	2	1	3	2025-11-21 02:34:48.167677+00	\N
