 AS edad_promedio\\\\n    FROM organizacion_empresario oe\\\\n    INNER JOIN organizations o ON oe.organizacionId = o.id\\\\n    INNER JOIN empresarios e ON oe.empresarioId = e.id\\\\n    WHERE o.pesca = 1\\\\n\\\\n    UNION ALL\\\\n\\\\n    SELECT 'agricultura', AVG(e.edad)\\\\n    FROM organizacion_empresario oe\\\\n    INNER JOIN organizations o ON oe.organizacionId = o.id\\\\n    INNER JOIN empresarios e ON oe.empresarioId = e.id\\\\n    WHERE o.agricultura = 1\\\\n\\\\n    UNION ALL\\\\n\\\\n    SELECT 'agroindustria', AVG(e.edad)\\\\n    FROM organizacion_empresario oe\\\\n    INNER JOIN organizations o ON oe.organizacionId = o.id\\\\n    INNER JOIN empresarios e ON oe.empresarioId = e.id\\\\n    WHERE o.agroindustria = 1\\\\n\\\\n    UNION ALL\\\\n\\\\n    SELECT 'pecuario', AVG(e.edad)\\\\n    FROM organizacion_empresario oe\\\\n    INNER JOIN organizations o ON oe.organizacionId = o.id\\\\n    INNER JOIN empresarios e ON oe.empresarioId = e.id\\\\n    WHERE o.pecuario = 1\\\\n) AS t\\\\nORDER BY actividad;\\\\n\\"}}","last_editor_id":1,"collection_location":"/","id":74,"last_edited_at":"2025-11-21T02:02:12.429718Z","dashboardcard_count":0,"collection_type":null,"display":"bar","archived_directly":false,"verified":null,"dashboard_id":null,"created_at":"2025-11-21T02:02:12.415513Z","model":"card"}	2026-03-04 01:16:00.522473+00	2026-03-04 01:16:00.522473+00	f	2025-11-25 03:34:03.909521+00	\N	f	5	\N	Edad promedio de las personas fundadoras por tipo de actividad productiva	f	2025-11-21 02:02:12.429718+00	0	[]	\N	1	74	bar	2025-11-25 03:33:58.165274+00	2	1	4	2025-11-21 02:02:12.415513+00	\N
